// Le a resposta da function e falha o workflow se nao foi 2xx ou se houve erros.
const code = $json.statusCode;
const body = $json.body || {};
const ok = typeof code === 'number' && code >= 200 && code < 300;
if (!ok) {
  throw new Error('sync-djen HTTP ' + (code ?? 'sem resposta') + ' ' + JSON.stringify(body).slice(0, 300));
}
const erros = Array.isArray(body.erros) ? body.erros : [];
if (erros.length > 0) {
  throw new Error('sync-djen retornou erros: ' + JSON.stringify(erros).slice(0, 300));
}
// Resumo pro log de execucao do n8n.
return { json: {
  janela: body.janela,
  publicacoes_recebidas: body.publicacoes_recebidas,
  vinculadas_novas: body.vinculadas_novas,
  orfas_novas: body.orfas_novas,
  andamentos_criados: body.andamentos_criados,
  ja_no_banco: body.ja_no_banco
} };
